import React from 'react'

export default function Hero() {
  return (
    <section className="w-full flex items-center justify-between py-20 px-10">
      
      {/* LEFT SIDE – TEXT */}
      <div className="max-w-xl space-y-6">
        <h1 className="text-4xl text-[#fc8506] font-bold  leading-tight">
          Find Lost Items. <br /> Return Found Items.
        </h1>

        <p className="text-gray-600 text-lg">
          A secure and simple way to report, track, and recover lost belongings on campus.
        </p>

        <button className="px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
          Report an Item
        </button>
      </div>

      {/* RIGHT SIDE – IMAGE */}
      <div>
        <img src='/heroimg.png' alt="Lost and Found" className="w-[500px]" />
      </div>
    </section>
  );
}

