"use client";
import React from 'react'
import { lostItems } from '../data/lostitem';
import { foundItems } from '../data/founditem';
import Card from './card';



const ItemSection = ({lostOrFound}) => {
    const itemToShow= lostOrFound==="lost"? lostItems: foundItems;
  return (
    <div className='bg-[#F9F8F6] flex justify-center items-start flex-wrap gap-6 px-6 pt-10'>
       { itemToShow.map((item)=>(
        <Card key={item.id} item={item}/>
        ))
    }
      
    </div>
  )
}

export default ItemSection
