import Image from "next/image";
import Link from "next/link";
const Card = ({ item }) => {
  console.log(item.name);
  return (
    <div className="bg-white shadow-sm hover:shadow-lg hover:shadow-blue-100 rounded-xl p-4 w-full max-w-sm h-90">
      <img
        className="w-full h-40 object-cover"
        src={item.image}
        alt={item.name}
      />

      <h3 className="mt-3 text-lg text-blue-800 font-semibold">
        Item: {item.name}
      </h3>
      <p className="text-sm text-gray-800">location: {item.location}</p>
      <p className="text-sm text-gray-800">Date: {item.date}</p>
      <div className="flex justify-baseline gap-2 mt-4">
        <button className="px-4 py-2 bg-orange-400 hover:bg-amber-400 text-black rounded-lg font-medium ">
          Claim
        </button>
        <button className="px-4 py-2 bg-blue-400 hover:bg-blue-300 border border-gray-400 rounded-lg">
          Details
        </button>
        <Link href={`/item/${item.id}`}>
        <button className="px-4 py-2 bg-[#80D8C3] border border-gray-400 rounded-lg">
          {item.status}
        </button>
        </Link>
      </div>
    </div>
  );
};

export default Card;
